// SPDX-License-Identifier: ISC
//! Replay of frozen rpc/jsonrpc/types vectors generated by an
//! in-package dump test running inside dcrd's types package at
//! release-v2.1.5.
//!
//! The dump pins the full registered method set with per-method flags
//! and usage text, a zero-value marshal of every struct type (field
//! names, json tags, declaration order, omitempty, and base
//! encodings), curated populated command and result marshals, the
//! parameter-parsing default round trips, the five custom Vin
//! marshaling shapes, spot help generation, and the string constants.

use std::collections::HashMap;

