use dcroxide_rpctypes::chainsvrwsresults as wsresults;
use dcroxide_rpctypes::{METHOD_TYPE_NAME, method, register_all};
use dcroxide_testutil::unhex;

const VECTORS: &str = include_str!("data/rpctypes_vectors.txt");

fn utf8(hex: &str) -> String {
    String::from_utf8(unhex(hex)).expect("utf8 payload")
}

fn s(v: &str) -> GoValue {
    GoValue::String(v.to_string())
}

fn strings(items: &[&str]) -> GoValue {
    GoValue::Array(items.iter().map(|v| s(v)).collect())
}

