/// The five Vin shapes from the dump plus the sigless regular input,
/// as full 12-field values of the [`results::vin`] descriptor.
fn vin_values() -> Vec<(&'static str, GoValue)> {
    let vin = |coinbase: &str,
               stakebase: &str,
               treasurybase: bool,
               treasury_spend: &str,
               txid: &str,
               vout: u64,
               tree: i64,
               sequence: u64,
               amount_in: f64,
               height: u64,
               index: u64,
               script_sig: GoValue| {
        GoValue::Struct(vec![
            s(coinbase),
            s(stakebase),
            GoValue::Bool(treasurybase),
            s(treasury_spend),
            s(txid),
            GoValue::Uint(vout),
            GoValue::Int(tree),
            GoValue::Uint(sequence),
            GoValue::Float64(amount_in),
            GoValue::Uint(height),
            GoValue::Uint(index),
            script_sig,
        ])
    };
    let sig = GoValue::Struct(vec![s("a<sm"), s("aabb")]);
    vec![
        (
            "coinbase",
            vin(
                "cbscript",
                "",
                false,
                "",
                "",
                0,
                0,
                4294967295,
                31.19,
                12,
                0,
                GoValue::Null,
            ),
        ),
        (
            "stakebase",
            vin(
                "",
                "sbscript",
                false,
                "",
                "",
                0,
                0,
                1,
                0.5,
                13,
                1,
                GoValue::Null,
            ),
        ),
        (
            "treasurybase",
            vin("", "", true, "", "", 0, 0, 2, 10.75, 14, 2, GoValue::Null),
        ),
        (
            "treasuryspend",
            vin(
                "",
                "",
                false,
                "tsscript",
                "",
                0,
                0,
                3,
                1e-8,
                15,
                3,
                GoValue::Null,
            ),
        ),
        (
            "regular",
            vin("", "", false, "", "t9", 3, 1, 4, 2.5, 16, 4, sig),
        ),
        (
            "regular-nosig",
            vin("", "", false, "", "t", 1, -1, 5, 0.25, 0, 0, GoValue::Null),
        ),
    ]
}

/// The populated TxRawResult from the dump, with the Vin slice carried
/// as raw pre-marshalled values exactly as a caller embeds custom
/// marshaler output.
fn raw_tx_value() -> GoValue {
    let vins: Vec<GoValue> = vin_values()
        .into_iter()
        .take(5)
        .map(|(_, v)| GoValue::Raw(results::marshal_vin(&v)))
        .collect();
    let spk = GoValue::Struct(vec![
        s("OP_DUP"),
        s("76a9"),
        GoValue::Int(1),
        s("pubkeyhash"),
        strings(&["Ds1"]),
        GoValue::Float64(0.5),
        GoValue::Uint(7),
    ]);
    let vout = GoValue::Struct(vec![
        GoValue::Float64(1.25),
        GoValue::Uint(0),
        GoValue::Uint(2),
        spk,
    ]);
    GoValue::Struct(vec![
        s("00ff"),
        s("txid9"),
        GoValue::Int(3),
        GoValue::Uint(8),
        GoValue::Uint(9),
        GoValue::Array(vins),
        GoValue::Array(vec![vout]),
        s("bh"),
        GoValue::Int(55),
        GoValue::Uint(2),
        GoValue::Int(10),
        GoValue::Int(1700000000),
        GoValue::Int(1700000001),
    ])
}

