/// The string constant battery.
fn strconst(name: &str) -> &'static str {
    match name {
        "ANAdd" => cmds::AN_ADD,
        "ANRemove" => cmds::AN_REMOVE,
        "ANOneTry" => cmds::AN_ONE_TRY,
        "NConnect" => cmds::N_CONNECT,
        "NRemove" => cmds::N_REMOVE,
        "NDisconnect" => cmds::N_DISCONNECT,
        "EstimateSmartFeeEconomical" => cmds::ESTIMATE_SMART_FEE_ECONOMICAL,
        "EstimateSmartFeeConservative" => cmds::ESTIMATE_SMART_FEE_CONSERVATIVE,
        "GRMAll" => cmds::GRM_ALL,
        "GRMRegular" => cmds::GRM_REGULAR,
        "GRMTickets" => cmds::GRM_TICKETS,
        "GRMVotes" => cmds::GRM_VOTES,
        "GRMRevocations" => cmds::GRM_REVOCATIONS,
        "GRMTSpend" => cmds::GRM_TSPEND,
        "GRMTAdd" => cmds::GRM_TADD,
        "AgendaInfoStatusDefined" => results::AGENDA_INFO_STATUS_DEFINED,
        "AgendaInfoStatusStarted" => results::AGENDA_INFO_STATUS_STARTED,
        "AgendaInfoStatusLockedIn" => results::AGENDA_INFO_STATUS_LOCKED_IN,
        "AgendaInfoStatusActive" => results::AGENDA_INFO_STATUS_ACTIVE,
        "AgendaInfoStatusFailed" => results::AGENDA_INFO_STATUS_FAILED,
        "BlockConnectedNtfnMethod" => ntfns::BLOCK_CONNECTED_NTFN_METHOD,
        "BlockDisconnectedNtfnMethod" => ntfns::BLOCK_DISCONNECTED_NTFN_METHOD,
        "NewTicketsNtfnMethod" => ntfns::NEW_TICKETS_NTFN_METHOD,
        "WorkNtfnMethod" => ntfns::WORK_NTFN_METHOD,
        "TSpendNtfnMethod" => ntfns::TSPEND_NTFN_METHOD,
        "ReorganizationNtfnMethod" => ntfns::REORGANIZATION_NTFN_METHOD,
        "TxAcceptedNtfnMethod" => ntfns::TX_ACCEPTED_NTFN_METHOD,
        "TxAcceptedVerboseNtfnMethod" => ntfns::TX_ACCEPTED_VERBOSE_NTFN_METHOD,
        "RelevantTxAcceptedNtfnMethod" => ntfns::RELEVANT_TX_ACCEPTED_NTFN_METHOD,
        "WinningTicketsNtfnMethod" => ntfns::WINNING_TICKETS_NTFN_METHOD,
        "MixMessageNtfnMethod" => ntfns::MIX_MESSAGE_NTFN_METHOD,
        other => panic!("unknown constant {other}"),
    }
}

#[test]
fn rpctypes_vectors() {
    let mut registry = Registry::new();
    register_all(&mut registry);

    let types = all_types();
    let marshals = marshalcmd_battery();
    let parses = parseparams_battery();
    let result_marshals = resultmarshal_battery();
    let vins = vin_values();

    let mut counts: HashMap<&str, usize> = HashMap::new();
    let mut zero_idx = 0usize;
    let mut cmd_idx = 0usize;
    let mut pp_idx = 0usize;
    let mut res_idx = 0usize;
    let mut vin_idx = 0usize;

    for line in VECTORS.lines() {
        if line.is_empty() {
            continue;
        }
        let parts: Vec<&str> = line.split('|').collect();
        *counts.entry(parts[0]).or_insert(0) += 1;
        match parts[0] {
            "methods" => {
                let methods = registry.registered_methods(METHOD_TYPE_NAME);
                assert_eq!(methods.join(","), parts[1], "{line}");
            }
            "flags" => {
                let flags = registry.method_usage_flags(&method(parts[1])).unwrap();
                let want: u32 = parts[2].parse().unwrap();
                assert_eq!(flags.0, want, "{line}");
            }
            "usage" => {
                let usage = registry.method_usage_text(&method(parts[1])).unwrap();
                assert_eq!(usage, utf8(parts[2]), "{line}");
            }
            "zeromarshal" => {
                let (name, typ) = &types[zero_idx];
                zero_idx += 1;
                assert_eq!(*name, parts[1], "zeromarshal order for {line}");
                let encoded = gojson::encode(typ, &GoValue::zero(typ));
                assert_eq!(encoded, utf8(parts[2]), "{line}");
            }
            "marshalcmd" => {
                let (label, id, cmd) = &marshals[cmd_idx];
                cmd_idx += 1;
                assert_eq!(*label, parts[1], "marshalcmd order for {line}");
                let encoded = marshal_cmd(&registry, "1.0", id, cmd)
                    .unwrap_or_else(|e| panic!("{line}: {e}"));
                assert_eq!(encoded, utf8(parts[2]), "{line}");
            }
            "parseparams" => {
                let (label, m, params) = &parses[pp_idx];
                pp_idx += 1;
                assert_eq!(*label, parts[1], "parseparams order for {line}");
                let cmd = dcroxide_dcrjson::parse_params(&registry, &method(m), params)
                    .unwrap_or_else(|e| panic!("{line}: {e}"));
                let encoded = marshal_cmd(&registry, "1.0", &RpcId::Int(1), &cmd)
                    .unwrap_or_else(|e| panic!("{line}: {e}"));
                assert_eq!(encoded, utf8(parts[2]), "{line}");
            }
            "resultmarshal" => {
                let (label, typ, value) = &result_marshals[res_idx];
                res_idx += 1;
                assert_eq!(*label, parts[1], "resultmarshal order for {line}");
                let encoded = gojson::encode(typ, value);
                assert_eq!(encoded, utf8(parts[2]), "{line}");
            }
            "vin" => {
                let (label, value) = &vins[vin_idx];
                vin_idx += 1;
                assert_eq!(*label, parts[1], "vin order for {line}");
                assert_eq!(results::marshal_vin(value), utf8(parts[2]), "{line}");
            }
            "help" => {
                let result_type = match parts[1] {
                    "getblock" => results::get_block_verbose_result(),
                    "gettxout" => results::get_tx_out_result(),
                    "ticketfeeinfo" => results::ticket_fee_info_result(),
                    other => panic!("unknown help row {other}"),
                };
                let (help, err) = registry.generate_help(
                    &method(parts[1]),
                    &HashMap::new(),
                    &[Some(result_type.ptr())],
                );
                assert_eq!(help, utf8(parts[2]), "{line}");
                let err = err.unwrap_or_else(|| panic!("{line}: expected missing key"));
                assert_eq!(err.description, utf8(parts[3]), "{line}");
            }
            "strconst" => {
                assert_eq!(strconst(parts[1]), parts[2], "{line}");
            }
            other => panic!("unknown vector op {other}"),
        }
    }

    assert_eq!(zero_idx, types.len());
    assert_eq!(cmd_idx, marshals.len());
    assert_eq!(pp_idx, parses.len());
    assert_eq!(res_idx, result_marshals.len());
    assert_eq!(vin_idx, vins.len());
    let expected: &[(&str, usize)] = &[
        ("methods", 1),
        ("flags", 105),
        ("usage", 105),
        ("zeromarshal", 171),
        ("marshalcmd", 26),
        ("parseparams", 14),
        ("resultmarshal", 10),
        ("vin", 6),
        ("help", 3),
        ("strconst", 31),
    ];
    for (op, want) in expected {
        assert_eq!(counts.get(op), Some(want), "row count for {op}");
    }
}
